svg.script:

(function() {
  var svgNS = "http://www.w3.org/2000/svg";
  var group = document.getElementById('checkerboard');

  // Configuration
  var cols = 12;
  var rows = 9;
  var cellW = 1600 / cols; // ~133.33
  var cellH = 110; // Slightly taller than 900/rows to allow for wave overflow

  // Wave distortion parameters
  var amplitude = 35; 
  var frequency = 0.018;
  var phaseShift = 0.012;

  // Helper to create path data for a single warped cell
  function createCellPath(x, y, w, h, row, col) {
    var points = [];
    // Generate 4 points with slight perturbations for a "hand-drawn" comic feel
    var jitter = 1.5;

    var p1x = x + (Math.random() - 0.5) * jitter;
    var p1y = y + getWaveY(x, row) + (Math.random() - 0.5) * jitter;

    var p2x = x + w + (Math.random() - 0.5) * jitter;
    var p2y = y + getWaveY(x + w, row) + (Math.random() - 0.5) * jitter;

    var p3x = x + w + (Math.random() - 0.5) * jitter;
    var p3y = y + h + getWaveY(x + w, row + 1) + (Math.random() - 0.5) * jitter;

    var p4x = x + (Math.random() - 0.5) * jitter;
    var p4y = y + h + getWaveY(x, row + 1) + (Math.random() - 0.5) * jitter;

    return "M " + p1x.toFixed(1) + " " + p1y.toFixed(1) + 
           " L " + p2x.toFixed(1) + " " + p2y.toFixed(1) + 
           " L " + p3x.toFixed(1) + " " + p3y.toFixed(1) + 
           " L " + p4x.toFixed(1) + " " + p4y.toFixed(1) + " Z";
  }

  function getWaveY(xPos, rowIndex) {
    return Math.sin(xPos * frequency + rowIndex * phaseShift) * amplitude;
  }

  // Render Grid
  for (var r = 0; r <= rows; r++) {
    for (var c = 0; c < cols; c++) {
      var path = document.createElementNS(svgNS, "path");

      // Checkerboard logic: alternate colors
      var isRed = (r + c) % 2 === 0;

      path.setAttribute("d", createCellPath(c * cellW, r * cellH - 50, cellW, cellH, r, c));
      path.setAttribute("fill", isRed ? "#E63946" : "#FFFFFF"); // Vintage Red & White
      path.setAttribute("stroke", "#000000");
      path.setAttribute("stroke-width", "6"); // Thick comic-book stroke
      path.setAttribute("stroke-linejoin", "round");
      path.setAttribute("stroke-linecap", "round");

      // Apply comic shadow filter only to red squares for depth
      if (isRed) {
        path.setAttribute("filter", "url(#comic-shadow)");
      }

      group.appendChild(path);
    }
  }
})();
